#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int first = -1, second = -1, x;
        for(int i=0;i<N;i++){
            scanf("%d",&x);
            if(x>first){
                if(x!=first){
                    second = first;
                }
                first = x;
            }else if(x<first && x>second){
                second = x;
            }
        }
        printf("%d\n", first+second);
    }
    return 0;
}

