import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        N = next(it)
        first = -1
        second = -1
        for _ in range(N):
            x = next(it)
            if x > first:
                if x != first:
                    second = first
                first = x
            elif x < first and x > second:
                second = x
        out.append(str(first + second))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

